                  <input type="file" ref={fileInputRef} className="hidden" accept=".csv" onChange={handleImport} />
              </div>
          </div>
        </DialogHeader>
        <Form {...form}>
          <div className="space-y-4">
            <ScrollArea className="h-[60vh] p-1 pr-4">
              <div className="space-y-4">
                {fields.map((field, index) => {
                  const isEditing = editingId === field.id;
