                                {entityUrl && (
                                    <Button size="sm" variant="outline" className="gap-1 h-8 shadow-sm" onClick={() => window.open(entityUrl, '_blank')}>
                                        <ExternalLink className="h-3.5 w-3.5" /> Portal
