                                                    {/* Input Row */}
                                                    <tr className="bg-muted/10">
                                                        <td className="p-2">
                                                            <Input 
                                                                placeholder="Ítem manual o descuento..." 
                                                                value={newGroupItem.description} 
                                                                onChange={(e) => setNewGroupItem({...newGroupItem, description: e.target.value})} 
