              ) : (
                <Table>
                    <TableHeader>
                        <TableRow>
                            <TableHead>Entidad</TableHead>
                            <TableHead>Tipo</TableHead>
                            <TableHead className="hidden md:table-cell">Recursos</TableHead>
                            <TableHead className="text-right">Acciones</TableHead>
