                            );
                        })}
                    </TableBody>
                </Table>
              )}
            </ScrollArea>


            <DialogFooter className="mt-4 pt-4 border-t">
              <Button type="button" variant="ghost" onClick={() => onOpenChange(false)}>Cancelar</Button>
              <Button type="button" onClick={handleDirectSave}>Guardar Cambios</Button>
            </DialogFooter>
          </div>
        </Form>
      </DialogContent>
    </Dialog>
  );
}

