                                            <span className="select-all">{entityCode}</span>
                                            <Button variant="ghost" size="icon" className="h-4 w-4 ml-1 hover:text-foreground" onClick={() => copyToClipboard(entityCode, 'Código Operador')}>
                                                <Copy className="h-3 w-3" />
