// --- Advisor Manager ---
interface AdvisorManagerDialogProps {
  isOpen: boolean;
  onOpenChange: (open: boolean) => void;
  advisors: Advisor[];
  onSave: (advisors: Advisor[]) => void;
}

export function AdvisorManagerDialog({ isOpen, onOpenChange, advisors: initialAdvisors, onSave }: AdvisorManagerDialogProps) {
  const { toast } = useToast();
  const [editingId, setEditingId] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const form = useForm<{ advisors: Advisor[] }>({
    resolver: zodResolver(advisorManagerSchema) as any,
    defaultValues: { advisors: [] },
  });

  const { control, reset, getValues } = form;

  const { fields, append, remove } = useFieldArray({
    control: control,
    name: "advisors",
  });

  useEffect(() => {
    if(isOpen) {
        reset({ advisors: initialAdvisors });
        setEditingId(null);
    }
  }, [initialAdvisors, isOpen, reset]);

  const handleDirectSave = () => {
    const data = getValues();
    onSave(data.advisors);
    toast({ title: 'Asesores actualizados', description: 'La lista de asesores ha sido guardada.' });
    onOpenChange(false);
  };

  const handleAddNew = () => {
    const newId = crypto.randomUUID();
    append({
        id: newId,
        name: '',
        commissionType: 'percentage',
        commissionValue: 10, 
        phone: '',
        email: '',
        paymentDetails: '',
    });
    setEditingId(newId);
  }

  // --- JSON EXPORT ---
  const handleExport = () => {
      const data = getValues().advisors;
      if (data.length === 0) {
          toast({ variant: "destructive", title: "Sin datos", description: "No hay asesores para exportar." });
          return;
      }

      const exportObject = {
          type: 'advisors_backup',
          version: '1.0',
          exportedAt: new Date().toISOString(),
          data: data
      };

      const jsonString = JSON.stringify(exportObject, null, 2);
      const blob = new Blob([jsonString], { type: 'application/json' });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(blob);
      link.download = `asesores_export_${new Date().toISOString().split('T')[0]}.json`;
      link.click();
  };

  // --- JSON IMPORT ---
  const handleImport = (e: ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (event) => {
          try {
              const content = event.target?.result as string;
              const parsed = JSON.parse(content);

              // Validación básica: soporta array directo o objeto con propiedad 'data'
              const importedData = Array.isArray(parsed) ? parsed : (Array.isArray(parsed.data) ? parsed.data : null);

              if (!importedData || importedData.length === 0) {
                  throw new Error("Formato inválido o vacío");
              }

              const currentAdvisors = getValues().advisors || [];
              const mergedAdvisors = [...currentAdvisors];

              let addedCount = 0;
              let updatedCount = 0;

              importedData.forEach((row: any) => {
                  if (!row.name) return;

                  // Intentar encontrar por ID o Nombre Normalizado
                  const safeName = normalizeString(row.name);
                  const existingIndex = mergedAdvisors.findIndex(
                      a => a.id === row.id || normalizeString(a.name) === safeName
                  );

                  const newAdvisor: Advisor = {
                      id: row.id || crypto.randomUUID(),
                      name: row.name,
                      commissionType: row.commissionType === 'fixed' ? 'fixed' : 'percentage',
                      commissionValue: Number(row.commissionValue) || 0,
                      phone: row.phone || '',
                      email: row.email || '',
                      paymentDetails: row.paymentDetails || ''
                  };

                  if (existingIndex >= 0) {
                      // Actualizar existente preservando ID original si no viene en el JSON
                      mergedAdvisors[existingIndex] = { 
                          ...mergedAdvisors[existingIndex], 
                          ...newAdvisor, 
                          id: mergedAdvisors[existingIndex].id 
                      }; 
                      updatedCount++;
                  } else {
                      mergedAdvisors.push(newAdvisor);
                      addedCount++;
                  }
              });

              reset({ advisors: mergedAdvisors });
              toast({ 
                  title: "Importación JSON Completada", 
                  description: `Se añadieron ${addedCount} y se actualizaron ${updatedCount} asesores.` 
              });

          } catch (error) {
              console.error(error);
              toast({ variant: "destructive", title: "Error de lectura", description: "El archivo JSON no es válido." });
          }
      };
      reader.readAsText(file);
      e.target.value = ''; // Reset input
  };

  return (
    <Dialog open={isOpen} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-3xl">
        <DialogHeader>
          <div className="flex justify-between items-center pr-8">
