    resolver: zodResolver(entityManagerStateSchema) as any,
    defaultValues: { entities: [] },
  });

  const { control, reset, getValues } = form;

  const { fields, append, remove } = useFieldArray({
    control,
    name: "entities",
  });

  useEffect(() => {
    if (isOpen) {
      reset({ entities: allEntities });
      setEditingId(null);
    }
  }, [allEntities, isOpen, reset]);

  const handleDirectSave = () => {
    const data = getValues();
    onSave(data.entities);
    toast({ title: 'Entidades actualizadas', description: 'La lista de entidades ha sido guardada.' });
    onOpenChange(false);
  };

  const handleAddNew = () => {
    const newId = crypto.randomUUID();
    append({
      id: newId,
      name: '',
      type: 'EPS',
      code: '',
      links: [],
      contacts: [],
    });
    setEditingId(newId);
  };

  const groupedContacts = (contacts: EntityContact[] = []) => {
    return contacts.reduce((acc, contact) => {
        (acc[contact.department] = acc[contact.department] || []).push(contact);
        return acc;
    }, {} as Record<string, EntityContact[]>);
  };

  // --- JSON EXPORT ---
  const handleExport = () => {
      const data = getValues().entities;
      if (data.length === 0) {
          toast({ variant: "destructive", title: "Sin datos", description: "No hay entidades para exportar." });
          return;
      }

      const exportObject = {
          type: 'entities_backup',
          version: '1.0',
          exportedAt: new Date().toISOString(),
          data: data
      };

      const jsonString = JSON.stringify(exportObject, null, 2);
      const blob = new Blob([jsonString], { type: 'application/json' });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(blob);
      link.download = `entidades_export_${new Date().toISOString().split('T')[0]}.json`;
      link.click();
  };

  // --- JSON IMPORT ---
  const handleImport = (e: ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (event) => {
          try {
              const content = event.target?.result as string;
              const parsed = JSON.parse(content);

              // Validación básica
              const importedData = Array.isArray(parsed) ? parsed : (Array.isArray(parsed.data) ? parsed.data : null);

              if (!importedData || importedData.length === 0) {
                  throw new Error("Formato inválido o vacío");
              }

              const currentEntities = getValues().entities || [];
              const mergedEntities = [...currentEntities];

              let addedCount = 0;
              let updatedCount = 0;

              importedData.forEach((row: any) => {
                  if (!row.name) return;

                  // En JSON, links y contacts ya vienen como arrays, no hay que parsear strings
                  const links = Array.isArray(row.links) ? row.links : [];
                  const contacts = Array.isArray(row.contacts) ? row.contacts : [];

                  const safeName = normalizeString(row.name);
                  const existingIndex = mergedEntities.findIndex(
                      ent => ent.id === row.id || normalizeString(ent.name) === safeName
                  );

                  const newEntity: Entity = {
                      id: row.id || crypto.randomUUID(),
                      name: row.name,
                      type: row.type || 'EPS',
                      code: row.code || '',
                      links: links,
                      contacts: contacts
                  };

                  if (existingIndex >= 0) {
                      mergedEntities[existingIndex] = { 
                          ...mergedEntities[existingIndex], 
                          ...newEntity, 
                          id: mergedEntities[existingIndex].id 
                      };
                      updatedCount++;
                  } else {
                      mergedEntities.push(newEntity);
                      addedCount++;
                  }
              });

              reset({ entities: mergedEntities });
              toast({ 
                  title: "Importación JSON Completada", 
                  description: `Se añadieron ${addedCount} y se actualizaron ${updatedCount} entidades.` 
              });
          } catch (error) {
              console.error(error);
              toast({ variant: "destructive", title: "Error de lectura", description: "El archivo JSON no es válido." });
          }
      };
      reader.readAsText(file);
      e.target.value = '';
  };

  return (
    <Dialog open={isOpen} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-4xl max-h-[90vh]">
        <DialogHeader>
           <div className="flex justify-between items-center pr-8">
              <div>
                <DialogTitle>Gestionar Entidades</DialogTitle>
                <DialogDescription>
                    Añade, edita o elimina las entidades del sistema.
                </DialogDescription>
              </div>
              <div className="flex gap-2">
                  <Button variant="outline" size="sm" onClick={handleExport} title="Exportar JSON">
                      <Download className="h-4 w-4 mr-1" /> JSON
                  </Button>
                  <Button variant="outline" size="sm" onClick={() => fileInputRef.current?.click()} title="Importar JSON">
                      <Upload className="h-4 w-4 mr-1" /> JSON
                  </Button>
                  <input type="file" ref={fileInputRef} className="hidden" accept=".json" onChange={handleImport} />
              </div>
          </div>
        </DialogHeader>
        <div className="flex justify-between items-center gap-4 py-2">
            <Button type="button" variant="outline" onClick={handleAddNew} className="h-9">
                <PlusCircle className="mr-2 h-4 w-4" /> Añadir Nueva Entidad
            </Button>
            <div className="flex bg-muted p-1 rounded-lg">
                <Button 
                    variant={viewMode === 'cards' ? 'secondary' : 'ghost'} 
