// --- Helper Components ---

// MODIFICADO: TabsContent ahora usa CSS para ocultar en lugar de no renderizar.
// Esto mantiene vivo el estado de los formularios en pestañas inactivas.
const TabsContent = ({ value, children, className }: { value: string, children?: ReactNode, className?: string }) => {
    const context = useContext(TabsContext);
    if (!context) return null;
    const { activeTab } = context;

    return (
        <div className={`${className} ${activeTab === value ? '' : 'hidden'}`}>
            {children}
        </div>
    );
};

// --- Client Credentials Viewer ---
interface ClientCredentialsDialogProps {
  isOpen: boolean;
  onOpenChange: (open: boolean) => void;
  client: Client | null;
  entities: Entity[];
}

export function ClientCredentialsDialog({ isOpen, onOpenChange, client, entities }: ClientCredentialsDialogProps) {
  const { toast } = useToast();
  const [visiblePasswords, setVisiblePasswords] = useState<Record<string, boolean>>({});

  const togglePassword = (id: string) => {
    setVisiblePasswords(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const copyToClipboard = (text: string, label: string) => {
    navigator.clipboard.writeText(text);
    toast({ title: "Copiado", description: `${label} copiado al portapapeles.` });
  };

  const handleShareCredential = (cred: any, entity: Entity | undefined) => {
      const url = entity?.links?.[0]?.url || '';
      const name = entity?.name || cred.entityName || 'Servicio';
      const type = entity?.type || cred.entityType || 'OPERADOR';
      const user = cred.username || '---';
      const pass = cred.password || '---';

      // Construcción del mensaje estilo WhatsApp con formato de cita
      const lines = [
          url ? `> ${url}` : null,
          `> *${type.toUpperCase()}* ${name}`,
          `> *USUARIO* ${user}`,
          `> *CLAVE* ${pass}`
      ];

      const textToCopy = lines.filter(Boolean).join('\n');

      navigator.clipboard.writeText(textToCopy);
      toast({ 
          title: "Acceso Copiado", 
          description: "Formato listo para pegar en WhatsApp.",
          variant: "default" 
      });
  };

  if (!client) return null;

  return (
    <Dialog open={isOpen} onOpenChange={onOpenChange}>
