                                type="submit" 
                                className={isRepairMode ? "bg-amber-600 hover:bg-amber-700 text-white" : ""}
                            >
                                {isRepairMode ? "Confirmar Reparación" : "Guardar Cliente"}
                            </Button>
                        </div>
                    </form>
                </Form>
            </DialogContent>
        </Dialog>
    );
}
